manual_title:'Manuel utilisateur',manual_subtitle:'Réception, visualisation et transfert de signaux Art-Net / sACN — guide complet pour les professionnels de la production en direct.',
toc_title:'Sommaire',toc_overview:'Aperçu',toc_quickstart:'Démarrage rapide',toc_dashboard:'Tableau de bord',toc_universe:'Visualiseur d\'univers',toc_devices:'Découverte d\'appareils',toc_forwarding:'Transfert',toc_signalflow:'Flux de signal',toc_settings:'Paramètres',toc_merge:'Moteur de fusion',toc_multinic:'Multi-NIC',toc_cluster:'Cluster / Redondance',toc_guardian:'Mode Guardian',toc_troubleshooting:'Dépannage',
